package problems;

import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.function.Function;
import java.util.stream.Collectors;

public class Duplicate {

    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 3};

        System.out.println("Contains Duplicate: " + containsDuplicate(nums));
        System.out.println("Contains Duplicate within window: " + containsDuplicateInWindow(nums, 2));
        System.out.println("Duplicate Elements: " + listOfDuplicates(nums));
    }

    /**
     * Check if array contains any duplicate.
     * 
     * Time: O(n), Space: O(n)
     * 
     * Using HashSet to track seen elements.
     */
    public static boolean containsDuplicate(int[] nums) {
        Set<Integer> seen = new HashSet<>();

        for (int num : nums) {
            if (!seen.add(num)) {
                return true;  // Duplicate found
            }
        }

        return false;
    }

    /**
     * Check if array contains duplicate within sliding window of size k.
     * 
     * Time: O(n), Space: O(k)
     * 
     * Maintains a sliding window set of at most k elements.
     * Returns true if duplicate found within k distance.
     */
    public static boolean containsDuplicateInWindow(int[] nums, int window) {
        Set<Integer> set = new HashSet<>();

        for (int i = 0; i < nums.length; i++) {
            if (set.contains(nums[i])) {
                return true;  // Found duplicate within window
            }

            set.add(nums[i]);

            // Maintain window size
            if (set.size() > window) {
                set.remove(nums[i - window]);
            }
        }

        return false;
    }

    /**
     * Return list of all duplicate elements.
     * 
     * Time: O(n), Space: O(n)
     * 
     * Uses Streams API to group by frequency and filter duplicates.
     */
    public static List<Integer> listOfDuplicates(int[] nums) {
        return Arrays.stream(nums)
                .boxed()
                .collect(Collectors.groupingBy(Function.identity(), Collectors.counting()))
                .entrySet()
                .stream()
                .filter(entry -> entry.getValue() > 1)
                .map(Map.Entry::getKey)
                .collect(Collectors.toList());
    }
}

// Example 1 (Contains Duplicate):
// Input: nums = [1,2,3,1]
// Output: true

// Example 2 (Duplicate in Window):
// Input: nums = [1,2,3,1], k = 3
// Output: true (indices 0 and 3, distance = 3)

// Example 3 (List Duplicates):
// Input: nums = [1,2,3,3,4,4,4]
// Output: [3, 4]
